func (c *current) onInput1(conf any) (any, error) {
	cs := conf.([]interface{})

	var set Set
	for i, e := range cs {
		con := e.(Conformance)
		switch con.(type) {
		case *Provisional:
			if i != 0 {
				return nil, fmt.Errorf("provisionality set at index %d; provisional annotations must be the first element of conformance", i)
			}
		case *Deprecated:
			if i == 0 || i != len(cs)-1 {
				return nil, fmt.Errorf("deprecation set at index %d; deprecation annotations must be the last element in a set of conformances", i)
			}
		}
		set = append(set, con)
	}
	return set, nil
}

func (p *parser) callonInput1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onInput1(stack["conf"])
}

