func (c *current) onEquationValue1(left, rest any) (any, error) {
	if rest == nil {
		return left, nil
	}
	multOps := rest.([]interface{})
	if len(multOps) == 0 {
		return left, nil
	}
	cv := left.(ComparisonValue)
	var mo *MathOperation
	for _, multOp := range multOps {
		mo = multOp.(*MathOperation)
		mo.Left = cv
		cv = mo
	}
	return cv, nil
}

